        "updated_by": "krn:user:user@example.com",
        "inclusive": true,
        "value": 35
        },
        "relative": {
        "increase": {
            "min": {
            "type": "value",
            "value": 0.5,
            "inclusive": true
            },
            "max": {
            "type": "percentage",
