            "value": 0.5,
            "inclusive": true
            },
            "max": {
            "type": "percentage",
            "value": 1,
            "inclusive": true
            }
        }
        }
    },
    "updater": {
        "number": {
        "min": {
            "source": "krn:ad:asset1/setpoint-min",
            "inclusive": true
        },
        "max": {
            "source": "krn:ad:asset1/setpoint-max",
            "inclusive": true
        }
        }
    },
    "created_by": "krn:user:user@example.com",
